import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"德和园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/dehe-yuan.md","filePath":"landmarks/summer-palace/dehe-yuan.md","lastUpdated":1784720050000}'),o={name:"landmarks/summer-palace/dehe-yuan.md"};function n(i,t,s,d,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="德和园" tabindex="-1">德和园 <a class="header-anchor" href="#德和园" aria-label="Permalink to &quot;德和园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1565715426586-dc9be734cfa3?w=1200&amp;q=80" alt="德和园大戏楼"></p><blockquote><p>&quot;一曲升平人尽欢，三层楼阁演乾坤。&quot; —— 慈禧太后的&quot;国家大剧院&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>德和园位于颐和园仁寿殿北侧，是清代三大戏楼之一，与紫禁城宁寿宫畅音阁、承德避暑山庄清音阁齐名，而德和园大戏楼是三者中规模最大、保存最完好的一座。它始建于光绪十七年（1891年），历时四年、耗银七十余万两建成，是颐和园重建工程中最昂贵的单体建筑之一。</p><p>大戏楼建成后，这里成为慈禧太后最主要的娱乐之所。慈禧一生嗜戏如命，每逢万寿节（她的生日）、节庆或心情烦闷时，便在德和园传戏，动辄连演数日。谭鑫培、杨小楼、王瑶卿、陈德霖等京剧名伶都曾在此供奉演出，中国京剧的许多经典剧目，都是在这座戏楼的氍毹之上打磨成型的。</p><p>园名&quot;德和&quot;，寓&quot;君子修德、和乐之至&quot;之意——只是当年真正&quot;和乐&quot;的，只有帘后的那一个人。如今德和园辟为清代宫廷戏曲文物陈列场所，戏装、砌末、戏单俱全，是了解京剧&quot;宫廷时代&quot;的最佳课堂。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清光绪十七年（1891）</td><td style="text-align:left;">德和园大戏楼开工</td></tr><tr><td style="text-align:left;">清光绪二十一年（1895）</td><td style="text-align:left;">建成，耗银七十余万两</td></tr><tr><td style="text-align:left;">1895-1908年</td><td style="text-align:left;">慈禧常年在此传戏，名伶供奉不断</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">随颐和园对外开放</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">辟为清代宫廷戏曲文物陈列馆</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>始建年代</strong></td><td style="text-align:left;">清光绪十七年至二十一年（1891-1895年）</td></tr><tr><td style="text-align:left;"><strong>核心建筑</strong></td><td style="text-align:left;">大戏楼（三层）、颐乐殿（观戏殿）</td></tr><tr><td style="text-align:left;"><strong>戏楼高度</strong></td><td style="text-align:left;">约21米，宽17米，为清代戏楼之冠</td></tr><tr><td style="text-align:left;"><strong>三层戏台</strong></td><td style="text-align:left;">上层福台、中层禄台、下层寿台</td></tr><tr><td style="text-align:left;"><strong>机关装置</strong></td><td style="text-align:left;">顶部天井辘轳可&quot;从天而降&quot;，寿台底部水法机关可喷水成泉</td></tr><tr><td style="text-align:left;"><strong>颐乐殿</strong></td><td style="text-align:left;">面阔七间，慈禧观戏专座，左右两廊为王公大臣陪侍席</td></tr></tbody></table><p>大戏楼三层相叠，可同时演出&quot;神、人、鬼&quot;三界同台的神话大戏：福台演天神下凡，禄台演人间故事，寿台演鬼魅地府，三层演员上下呼应，配合天井、地井的机关升降，上天入地，场面恢宏。</p><p>寿台地板下设水法机关，演《水漫金山》等戏时可喷水成柱，营造水景。戏楼对面是颐乐殿，殿内正中设慈禧御座，左右两廊则为王公大臣陪侍看戏之处——陪看也是差事，一坐一整天，不得离席，不得喧哗。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="慈禧的-戏单" tabindex="-1">慈禧的&quot;戏单&quot; <a class="header-anchor" href="#慈禧的-戏单" aria-label="Permalink to &quot;慈禧的&quot;戏单&quot;&quot;">​</a></h3><p>慈禧看戏极为讲究，德和园演出前须先呈&quot;戏单&quot;，由她亲自圈定剧目和演员。据清宫档案记载，一次万寿庆典，德和园连演九天，剧目多达数十出，谭鑫培的《定军山》、杨小楼的《长坂坡》都是慈禧反复点演的&quot;保留剧目&quot;。</p><p>演员唱错一字、走错一步，轻则罚俸，重则革退；唱得合意，则当场赏赐银两、玉件，伶人们的荣辱系于帘后一人之喜怒。</p><h3 id="三层戏台的机关" tabindex="-1">三层戏台的机关 <a class="header-anchor" href="#三层戏台的机关" aria-label="Permalink to &quot;三层戏台的机关&quot;">​</a></h3><p>德和园大戏楼最令人称道的是其精巧机关。顶层设有辘轳绞车，可将扮演神仙的演员自天而降；底层寿台下有水井和水池，演出时通过水法将水抽至台上，喷涌成泉。传说演《天河配》时，台上真的能下起&quot;雨&quot;来，鹊桥相会，水雾缭绕，令观者如临其境。这套机关即便以今日舞台技术衡量，仍堪称巧思。</p><h3 id="不插电的-天然音响" tabindex="-1">不插电的&quot;天然音响&quot; <a class="header-anchor" href="#不插电的-天然音响" aria-label="Permalink to &quot;不插电的&quot;天然音响&quot;&quot;">​</a></h3><p>在没有扩音设备的年代，三层大戏楼本身就是一台巨型音响。三重屋檐与中空木构形成共鸣腔，台下还有水井聚音——演员在寿台开腔，声音经井腔反射、梁架共鸣，字字清晰地送到颐乐殿御座前。</p><p>老艺人回忆，在德和园唱戏&quot;不敢用全力&quot;，因为共鸣太好，稍一发力便声震屋瓦。慈禧坐在颐乐殿正中听音，正是这座戏楼声学设计的&quot;皇帝位&quot;。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>三层大戏楼</strong>：仰观福、禄、寿三层戏台，想象当年&quot;神仙下凡、鬼魅出地&quot;的立体演出，是清代舞台工程的巅峰。</li><li><strong>水法机关遗址</strong>：寿台底部的水井与水法装置仍存，是&quot;喷水成泉&quot;舞台特效的实物证据。</li><li><strong>颐乐殿御座</strong>：慈禧观戏专座与两廊陪座保存完好，可直观感受&quot;一人看戏、满朝陪侍&quot;的宫廷生活。</li><li><strong>戏装与砌末展</strong>：殿内常设清宫戏装、砌末（道具）陈列，刺绣华美，是了解京剧衣箱制的好材料。</li><li><strong>名伶史料</strong>：展室中有谭鑫培等供奉伶人的戏单、剧照与档案，串起一部京剧&quot;入宫史&quot;。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>中轴对景</strong>：站在颐乐殿前广场正中，同框收入三层飞檐与观戏殿，纵深感极强。</li><li><strong>仰拍福台</strong>：绕到戏楼侧面仰拍三层檐角，最显21米戏楼的体量。</li><li><strong>戏装细节</strong>：展室光线稳定，适合拍摄刺绣纹样（禁用闪光灯）。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>德和园为园中园，需持联票或另购5元门票；联票游客直接入院即可。</li><li>院内戏楼前广场是合影热点，想拍空镜建议开园后尽早抵达。</li><li>大戏楼与颐乐殿之间的中轴线视角最佳，能同时收入三层飞檐与观戏殿全貌。</li><li>从<a href="/beijing-travel-guide/landmarks/summer-palace/renshou-dian.html">仁寿殿</a>步行约5分钟即达，两处建议串联参观，一动（听政）一静（看戏），正是慈禧生活的两面。</li><li>逛完德和园，可沿仁寿殿南路前往乐寿堂、<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>，继续<a href="/beijing-travel-guide/landmarks/summer-palace/">东宫门线</a>的行程。</li><li>对京剧有兴趣的话，留足一小时细看展室——那些戏单上的名字，半部京剧史都在里面。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：德和园需要单独购票吗？</strong></p><p>德和园属园中园，单独购票5元；持颐和园联票可直接进入，联票更划算。</p><p><strong>Q：现在德和园里还唱戏吗？</strong></p><p>日常以宫廷戏曲文物陈列为主，没有固定演出；逢年过节或重大活动时偶有专场，以园方公告为准。</p><p><strong>Q：德和园和故宫畅音阁哪个更大？</strong></p><p>德和园大戏楼高约21米，比紫禁城畅音阁（约20.7米）略高，是清代三大戏楼中体量最大、保存最完好的一座。</p><p><strong>Q：慈禧看戏坐哪儿，大臣坐哪儿？</strong></p><p>慈禧独坐戏楼对面的颐乐殿正座，王公大臣在东西两廊陪侍看戏——陪坐也是一桩苦差，如今座位陈设仍完好可看。</p><hr><p><strong>📍 位置</strong>：颐和园东部，仁寿殿北侧 <strong>⏱️ 建议游览</strong>：40-60分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',39)])])}const p=a(o,[["render",n]]);export{q as __pageData,p as default};
